SELECT COUNT(DISTINCT LPP.FK_PRODBIB) AS TOTAL FROM LATTES_P_PRODBIB LPP JOIN LATTES_PRODBIB LPB ON LPB.PK = LPP.FK_PRODBIB JOIN SERVIDOR S ON S.PK_SIAPE = LPP.FK_SIAPE WHERE LOWER(COALESCE(LPB.TIPO, '')) = 'artigo' AND LOWER(COALESCE(LPB.NATUREZA, '')) = 'completo' AND LOWER(COALESCE(S.AREA_INGRESSO, '')) LIKE '%agronomia%' AND (LOWER(COALESCE(S.SIGLA_CAMPUS, '')) = 'inh' OR LOWER(COALESCE(S.CAMPUS_ATUAL, '')) LIKE '%inhumas%') AND LOWER(COALESCE(LPB.ANO, '')) LIKE '%2021%'